# stripe_webhook.py — Stripe signature verification + Redis queue
import stripe
import redis
import json
from fastapi import FastAPI, Request, HTTPException
from fastapi.responses import JSONResponse
import os

app = FastAPI()
stripe.api_key = os.environ["STRIPE_SECRET_KEY"]
WHSEC = os.environ["STRIPE_WEBHOOK_SECRET"]  # whsec_...

# Redis for idempotency store and background queue
redis_client = redis.Redis(host="localhost", port=6379, decode_responses=True)

@app.post("/webhook/stripe")
async def stripe_webhook(request: Request):
    payload = await request.body()
    sig_header = request.headers.get("Stripe-Signature", "")

    try:
        # Stripe SDK validates timestamp + HMAC in one call
        event = stripe.Webhook.construct_event(payload, sig_header, WHSEC)
    except stripe.error.SignatureVerificationError:
        raise HTTPException(status_code=400, detail="Invalid Stripe signature")
    except ValueError:
        raise HTTPException(status_code=400, detail="Invalid payload")

    event_id = event["id"]

    # Idempotency: skip if already processed
    if redis_client.sismember("processed_webhook_ids", event_id):
        return JSONResponse({"status": "already processed"})

    # Push to Redis list for async worker consumption
    redis_client.rpush("webhook_queue", json.dumps({
        "event_id": event_id,
        "event_type": event["type"],
        "data": event["data"]["object"],
    }))

    # Mark as seen AFTER queueing to avoid losing events on crash
    redis_client.sadd("processed_webhook_ids", event_id)
    redis_client.expire("processed_webhook_ids", 86400 * 7)  # 7-day TTL

    return JSONResponse({"status": "queued"}, status_code=200)

# --- Background worker (separate process) ---
def consume_webhook_queue():
    while True:
        _, raw = redis_client.blpop("webhook_queue", timeout=30) or (None, None)
        if not raw:
            continue
        event = json.loads(raw)
        handle_event(event["event_type"], event["data"])

def handle_event(event_type: str, data: dict):
    if event_type == "payment_intent.succeeded":
        print(f"Payment succeeded: {data['id']} amount={data['amount']}")
    elif event_type == "invoice.payment_failed":
        print(f"Invoice failed: {data['id']}")
